mapper.select:
SELECT tenant_id
FROM account_import_detail
WHERE online_phase = #{queuedPhase}
  AND parse_result = #{successParseResult}
  AND account_id IS NOT NULL
  AND login_result IS NULL
GROUP BY tenant_id
ORDER BY MIN(id) ASC
LIMIT #{limit}

mapper.update:
UPDATE account_import_detail
SET online_phase = #{settlement.settledPhase},
    login_result = #{settlement.loginResult},
    login_settled_at = #{settlement.loginSettledAt},
    login_reason = #{settlement.loginReason}
WHERE account_id = #{settlement.accountId}
  AND parse_result = #{settlement.successParseResult}
  AND online_phase = #{settlement.dispatchedPhase}
  AND login_result IS NULL
  AND online_dispatched_at IS NOT NULL
  AND online_dispatched_at <= #{settlement.loginSettledAt}

mapper.select:
SELECT d.id, d.line_no AS lineNo, d.ws_phone AS wsPhone, d.parse_result AS parseResult, d.raw_payload AS rawPayload, d.source_entry_name AS sourceEntryName FROM account_import_detail d JOIN account_import_batch b ON d.batch_id = b.id AND d.tenant_id = b.tenant_id WHERE d.batch_id = #{batchId}
AND d.parse_result = 1 AND d.parse_result IN (2, 3, 4)
ORDER BY d.line_no ASC
